external_knowledge:
- "more vaccinated people" refers to the count of partially vaccinated individuals; 
- "average rate" here indicates the average partially vaccinated rate for each territorial authority;
- Cumulative sum refers to the sum of partially vaccinated individuals within each territorial authority, accumulated by age group.

sql:
SELECT AVG(population) AS average_population
FROM territorial_authorities
WHERE region = 'Auckland';

SELECT age_group_id, age_range, COUNT(description) AS number_of_age_groups
FROM age_groups
GROUP BY age_group_id, age_range;

SELECT date, partially_vaccinated, completed_primary_course
FROM vaccination_data
ORDER BY date DESC;

SELECT ta.authority_name, vd.partially_vaccinated, vd.completed_primary_course, vd.date
FROM vaccination_data vd
JOIN territorial_authorities ta ON vd.authority_id = ta.authority_id;

SELECT authority_id, SUM(completed_primary_course) AS total_completed_primary_course
FROM vaccination_data
WHERE authority_id = 0;
